previewCss:
.darma-loader-cssloaders-github-16 {
  display: inline-block;
  width: 92px;
  height: 10px;
  border-radius: 999px;
  background: color-mix(in srgb, var(--loader-color, #ef4444) 16%, transparent);
  overflow: hidden;
}
.darma-loader-cssloaders-github-16::before {
      content: "";
      display: block;
      width: 42%;
      height: 100%;
      border-radius: inherit;
      background: linear-gradient(90deg, var(--loader-color, #ef4444), var(--loader-secondary-color, #fecaca));
      animation: darma-loader-cssloaders-github-16-progressSlide 0.9s ease-in-out infinite;
    }
    @keyframes darma-loader-cssloaders-github-16-progressSlide { 0% { transform: translateX(-120%); } 100% { transform: translateX(260%); } }

